I'll help you create the SQLite table, insert sample data, and query for products with price greater than 10. Let me execute these SQL statements:

{"tool": "run_sql", "args": {"sql": "-- Step 1: Create the products table
CREATE TABLE IF NOT EXISTS products (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    price REAL NOT NULL
);

-- Step 2: Insert 3 sample rows
INSERT INTO products (name, price) VALUES ('Widget A', 15.99);
INSERT INTO products (name, price) VALUES ('Widget B', 8.50);
INSERT INTO products (name, price) VALUES ('Widget C', 22.75);

-- Step 3: Select all products with price greater than 10
SELECT * FROM products WHERE price > 10;"}}

